use std::collections::HashMap;

fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let total: i64 = nums.iter().sum();
    let mut prefix_sum = 0;
    let mut dp_prev = 0;
    let mut mod_map = HashMap::new();
    mod_map.insert(0, 0);
    for num in nums {
        prefix_sum += num;
        let current_mod = prefix_sum % k;
        let possible = if mod_map.contains_key(&current_mod) {
            prefix_sum + mod_map[&current_mod]
        } else {
            0
        };
        let dp_current = if mod_map.contains_key(&current_mod) {
            std::cmp::max(dp_prev, possible)
        } else {
            dp_prev
        };
        let current_value = dp_current - prefix_sum;
        if mod_map.contains_key(&current_mod) {
            if current_value > mod_map[&current_mod] {
                mod_map.insert(current_mod, current_value);
            }
        } else {
            mod_map.insert(current_mod, current_value);
        }
        dp_prev = dp_current;
    }
    total - dp_prev
}
